-- テーブルの構造 `prescription_io_debug_snapshots`
--

CREATE TABLE `prescription_io_debug_snapshots` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `company_uid` varchar(32) NOT NULL,
  `branch_uid` varchar(32) NOT NULL,
  `tenant_id` int(11) NOT NULL,
  `parse_job_id` bigint(20) UNSIGNED DEFAULT NULL,
  `prescription_id` bigint(20) UNSIGNED DEFAULT NULL,
  `stage` varchar(64) NOT NULL,
  `stage_label` varchar(160) NOT NULL,
  `model_name` varchar(120) DEFAULT NULL,
  `content_type` varchar(40) NOT NULL DEFAULT 'json',
  `snapshot_json` longtext DEFAULT NULL,
  `snapshot_text` longtext DEFAULT NULL,
  `source_hash` char(64) DEFAULT NULL,
  `created_by_user_id` bigint(20) UNSIGNED DEFAULT NULL,
  `created_at` datetime NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

