--
-- テーブルの構造 `prescription_medications`
--

CREATE TABLE `prescription_medications` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `prescription_id` bigint(20) UNSIGNED NOT NULL,
  `sort_order` int(11) NOT NULL DEFAULT 1,
  `drug_master_id` bigint(20) UNSIGNED DEFAULT NULL,
  `drug_name` varchar(160) NOT NULL,
  `generic_name` varchar(255) DEFAULT NULL COMMENT '人間確認後の一般名候補',
  `brand_name` varchar(255) DEFAULT NULL COMMENT '人間確認後の商品名候補',
  `raw_drug_text` text DEFAULT NULL COMMENT '画像内で読めた薬品名関連行。一般名・商品名を改行で保持',
  `ai_drug_name` varchar(255) DEFAULT NULL COMMENT 'AIが最初に読んだ代表薬品名',
  `ai_generic_name` varchar(255) DEFAULT NULL COMMENT 'AIが最初に読んだ一般名候補',
  `ai_brand_name` varchar(255) DEFAULT NULL COMMENT 'AIが最初に読んだ商品名候補',
  `drug_name_relation_type` varchar(60) NOT NULL DEFAULT 'unknown' COMMENT 'single/generic_brand_pair/multiple_candidates/unknown',
  `usage_text` varchar(160) DEFAULT NULL,
  `dose_text` varchar(80) DEFAULT NULL,
  `days_count` int(11) DEFAULT NULL,
  `amount_text` varchar(80) DEFAULT NULL,
  `stock_status` enum('adopted','in_stock','low_stock','not_stocked','unknown') NOT NULL DEFAULT 'unknown',
  `needs_check` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `normalized_drug_name` varchar(255) DEFAULT NULL,
  `source_confidence` decimal(6,2) DEFAULT NULL,
  `correction_status` varchar(40) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

